#include <bits/stdc++.h>
using namespace std;

int n, a[400005];
long long s[400005];

int main() {
    cin >> n;
    bool flag = true;
    int maxn = INT_MIN;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        a[i + n] = a[i];
        if (a[i] >= 0) {
            flag = false;
        }
        if (a[i] > maxn) {
            maxn = a[i];
        }
        // cout << maxn << ' ';
    }
    if (flag) {
        cout << maxn;
        return 0;
    }
    for (int i = 1; i <= 2 * n; i++) {
        s[i] = s[i - 1] + a[i];
        // cout << s[i] << ' ';
    }
    // cout << endl;
    deque<int> q;
    long long ans = INT_MIN;
    for (int i = 1; i <= 2 * n; i++) {
        // if (s[i] <= 0) {
        //     continue;
        // }
        while (!q.empty() && s[q.back()] <= s[i]) {
            q.pop_back();
        }
        q.push_back(i);
        if (i >= n) {
            // if (q.front() == i - n + 1) continue;
            ans = max(ans, s[q.front()] - s[i - n + 1]);
            // printf("%lld %lld  %lld\n", s[q.front()], s[i - n + 1], s[q.front()] - s[i - n + 1]);
            if (i - q.front() + 1 >= n) {
                q.pop_front();
            }
        }
    }
    cout << ans;
    return 0;
}
